using System.Collections.Generic;\n\nnamespace Backend.Application.Factories\n{\n    public interface IProductCalculatorFactory\n    {\n        void RegisterCalculator(string productType, IProductCalculator calculator);\n        IProductCalculator GetCalculator(string productType);\n    }\n\n    public class ProductCalculatorFactory : IProductCalculatorFactory\n    {\n        private readonly Dictionary<string, IProductCalculator> _calculators = new Dictionary<string, IProductCalculator>();\n\n        public void RegisterCalculator(string productType, IProductCalculator calculator)\n        {\n            if (!_calculators.ContainsKey(productType))\n            {\n                _calculators[productType] = calculator;\n            }\n        }\n\n        public IProductCalculator GetCalculator(string productType)\n        {\n            _calculators.TryGetValue(productType, out var calculator);\n            return calculator;\n        }\n    }\n}